INSERT INTO public.data_brokers (slug, name, website, opt_out_url, opt_out_difficulty, opt_out_time_estimate, requires_id, requires_phone, requires_captcha, instructions, priority, is_active)
VALUES
  ('acxiom', 'Acxiom', 'https://www.acxiom.com', 'https://isapps.acxiom.com/optout/optout.aspx', 'medium', '10 minutes', false, false, true, '1. Visit the Acxiom opt-out form\n2. Fill in your name, email, address, and date of birth\n3. Choose which data products to opt out of (recommend selecting all)\n4. Submit the form\n5. Confirm via email link', 'crucial', true),
  ('epsilon', 'Epsilon', 'https://www.epsilon.com', 'https://www.epsilon.com/us/privacy-policy', 'hard', '15 minutes', false, true, false, '1. Email optout@epsilon.com with subject "Opt-Out Request"\n2. Include your full name, current address, previous addresses (last 5 years), and phone number\n3. State you want to be removed from all marketing databases\n4. Wait 30-60 days for confirmation', 'crucial', true),
  ('lexisnexis', 'LexisNexis', 'https://www.lexisnexis.com', 'https://optout.lexisnexis.com/', 'hard', '20 minutes', true, false, true, '1. Visit the LexisNexis opt-out portal\n2. Fill out the Privacy Request Form\n3. Provide ID verification (driver''s license or passport)\n4. Submit notarized opt-out request via mail if required\n5. Allow 30 days for processing', 'crucial', true),
  ('peekyou', 'PeekYou', 'https://www.peekyou.com', 'https://www.peekyou.com/about/contact/optout/', 'easy', '5 minutes', false, false, true, '1. Search for your profile on PeekYou\n2. Copy the unique ID from your profile URL\n3. Visit the opt-out page\n4. Paste the ID and provide your email\n5. Confirm via email link', 'high', true),
  ('usa-people-search', 'USA-People-Search', 'https://www.usa-people-search.com', 'https://www.usa-people-search.com/manage', 'easy', '5 minutes', false, false, true, '1. Search for yourself on USA-People-Search\n2. Click on your profile\n3. Click "Remove This Record" at the bottom\n4. Enter your email and complete CAPTCHA\n5. Confirm removal via email', 'high', true),
  ('zabasearch', 'ZabaSearch', 'https://www.zabasearch.com', 'https://www.intelius.com/opt-out', 'medium', '10 minutes', true, false, true, '1. ZabaSearch is owned by Intelius — use the Intelius opt-out\n2. Search for yourself on ZabaSearch first to confirm listing\n3. Visit the Intelius opt-out page\n4. Submit ID verification\n5. Allow 7-14 days for removal', 'high', true),
  ('411', '411.info', 'https://www.411.info', 'https://www.411.info/manage/optout', 'easy', '5 minutes', false, false, true, '1. Search for yourself on 411.info\n2. Locate your listing\n3. Click "Remove" or visit the opt-out form\n4. Enter the URL of your listing and your email\n5. Confirm removal via email link', 'high', true),
  ('yellowpages', 'YellowPages', 'https://www.yellowpages.com', 'https://www.yellowpages.com/about/our-policies/privacy-policy', 'medium', '10 minutes', false, true, false, '1. Email privacy@yellowpages.com\n2. Subject: "Opt-Out Request"\n3. Include name, address, phone number to remove\n4. Reference YellowPages privacy policy section on data removal\n5. Allow 30 days for processing', 'normal', true),
